package com.promonts.dto;import com.promonts.domain.notice.Notice;import lombok.*;import java.time.LocalDateTime;@Data @NoArgsConstructor @AllArgsConstructor @Builder public class NoticeListResponse{private Long id;private String title;private String authorName;private LocalDateTime createdAt;public static NoticeListResponse from(Notice notice){return NoticeListResponse.builder().id(notice.getId()).title(notice.getTitle()).authorName(notice.getAuthor().getName()).createdAt(notice.getCreatedAt()).build();}}
